module median_filter (
    input a,
    input b,
    input c,
    output reg median
);
  wire _tap_a = a & {1{1'b1}};

    always @(*) begin
        if ((a >= b && a <= c) || (a <= b && a >= c))
            median = a;
        else if ((b >= a && b <= c) || (b <= a && b >= c))
            median = b;
        else
            median = c;
    end
endmodule
